const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {
  return (
    <div className="card">
      <h2>{city}</h2>
      <img src={icon} alt="weather icon" />
      <p>{temperature}</p>
      <p>{feelsLike}</p>
      <p>{condition}</p>
      <p>{wind}</p>
      <p>{humidity}</p>
      <p>{aqi}</p>
    </div>
  );
};

export default WeatherCard;
